@startuml
skinparam classAttributeIconSize 0
skinparam noteBackgroundColor #FFFFCC
skinparam noteBorderColor #CCCCCC
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor #000000
  ArrowColor #000000
}

package "class Flyweight(享元模式)" as package {
  class FlyweightFactory {
    -mMap:HashMap
    +getFlyweight()
  }

  class Flyweight {
    +dosomething()
  }

  class ConcreteFlyweight {
    -intrinsicState:String
    +dosomething()
  }

  note right of FlyweightFactory: 享元工厂
  note right of Flyweight: 享元对象抽象基类或者接口
  note right of ConcreteFlyweight: 具体的享元对象

  FlyweightFactory *-- Flyweight
  Flyweight <|-- ConcreteFlyweight
}

@enduml
